export interface EmptyStateProps { title: string; description?: string; }
export function EmptyState({ title, description }: EmptyStateProps): JSX.Element { return <div className="rounded-2xl border border-dashed border-cyan-300/30 bg-cyan-300/5 p-6 text-center"><p className="font-semibold text-cyan-100">{title}</p>{description ? <p className="mt-1 text-sm text-slate-400">{description}</p> : null}</div>; }
