import { DashboardCard } from '@/components/DashboardCard';
import { EmptyState } from '@/components/EmptyState';
import { GradeList } from '@/components/GradeList';
import { SchedulePreview } from '@/components/SchedulePreview';
import { useChromeStorage } from '@/hooks/useChromeStorage';
export function PopupApp(): JSX.Element { const [gradeSnapshot] = useChromeStorage('gradeSnapshot', { grades: [], capturedAt: '' }); const [scheduleSlots] = useChromeStorage('scheduleSlots', []); return <main className="w-96 space-y-4 bg-[radial-gradient(circle_at_top_left,rgba(34,211,238,0.24),transparent_32%),linear-gradient(180deg,#020617,#0f172a)] p-4 text-slate-100"><header className="rounded-3xl border border-cyan-300/20 bg-white/10 p-4 shadow-[0_0_40px_rgba(34,211,238,0.18)]"><p className="text-[10px] font-black uppercase tracking-[0.2em] text-cyan-200">Player HUD</p><h1 className="mt-1 text-2xl font-black text-white">SIASE Plus</h1><p className="mt-1 text-xs text-slate-300">Tu progreso académico en modo dashboard.</p></header><DashboardCard title="Calificaciones">{gradeSnapshot.grades.length ? <GradeList grades={gradeSnapshot.grades} /> : <EmptyState title="Sin calificaciones cacheadas" description="Abre Calificaciones en SIASE para llenar este panel." />}</DashboardCard><DashboardCard title="Horario">{scheduleSlots.length ? <SchedulePreview slots={scheduleSlots.slice(0, 5)} /> : <EmptyState title="Sin horario cacheado" description="Abre Horario en SIASE para activar la vista rápida." />}</DashboardCard></main>; }
